<template>
  <div class="action-debug-workspace flex flex-col h-full p-2 gap-2 overflow-auto">
    <!-- 操作选择器 -->
    <section class="action-selector bg-white rounded-lg border border-[var(--el-border-color-lighter)] p-3 shadow-sm">
      <div class="flex items-center justify-between mb-2">
        <label class="text-xs font-medium text-[var(--el-text-color-secondary)] flex items-center gap-1">
          <el-icon :size="12"><Search /></el-icon>
          选择操作
        </label>
        <el-tag size="small" type="info" effect="plain">{{ registeredActions.length }} 个可用</el-tag>
      </div>

      <el-select
        v-model="selectedActionId"
        placeholder="搜索或选择要调试的操作..."
        class="w-full"
        filterable
        :loading="loadingActions"
        @change="onActionChange"
      >
        <template #prefix><el-icon><Search /></el-icon></template>
        <el-option
          v-for="action in registeredActions"
          :key="action.id"
          :value="action.id"
          :label="action.name"
        >
          <div class="flex items-center gap-2 py-1">
            <el-icon :size="14"><component :is="getActionIcon(action.type || 'interaction')" /></el-icon>
            <span class="flex-1">{{ action.name }}</span>
            <el-tag size="small" type="info" effect="plain" class="!text-[10px]">{{ action.type || 'other' }}</el-tag>
          </div>
        </el-option>
      </el-select>

      <p v-if="currentAction?.description && !compactMode" class="text-xs text-[var(--el-text-color-secondary)] mt-2 mb-0 leading-relaxed line-clamp-2">
        {{ currentAction.description }}
      </p>
    </section>

    <!-- 参数配置区（动态表单） -->
    <section v-if="currentAction?.parameters?.length > 0" class="params-config bg-white rounded-lg border border-[var(--el-border-color-lighter)] p-3 shadow-sm flex-1 overflow-y-auto">
      <div class="flex items-center justify-between mb-3">
        <label class="text-xs font-medium text-[var(--el-text-color-secondary)] flex items-center gap-1">
          参数配置
          <el-badge :value="requiredParamsCount" :max="99" class="ml-1" />
        </label>
        <el-button size="small" text @click="resetParams" :disabled="!hasCustomParams">
          <el-icon><RefreshRight /></el-icon> 重置
        </el-button>
      </div>

      <el-form label-position="top" size="small">
        <el-form-item
          v-for="param in currentAction.parameters"
          :key="param.name"
          :required="param.required"
          class="mb-3"
        >
          <template #label>
            <div class="flex items-center gap-1">
              <span>{{ param.name }}</span>

              <!-- 变量预览指示器 -->
              <el-tooltip
                v-if="actionParams[param.name]?.includes('{{')"
                :content="`预览: ${previewResults[param.name] || '解析中...'}`"
                placement="top"
                effect="light"
              >
                <el-icon class="text-purple-500 cursor-help animate-pulse" :size="12"><InfoFilled /></el-icon>
              </el-tooltip>
            </div>
          </template>

          <div class="relative">
            <el-input
              v-model="actionParams[param.name]"
              :placeholder="`默认: ${param.default ?? '(空)'}`"
              clearable
              @blur="onParamBlur(param.name)"
            />

            <!-- 预览结果气泡 -->
            <transition name="el-zoom-in-top">
              <div
                v-if="previewResults[param.name] && showPreview[param.name]"
                class="absolute z-20 top-full left-0 right-0 mt-1 p-2 rounded-lg shadow-lg text-xs font-mono"
                :class="previewResults[param.name].startsWith('(错误)') ? 'bg-red-50 text-red-700 border border-red-200' : 'bg-green-50 text-green-700 border border-green-200'"
              >
                {{ previewResults[param.name] }}
              </div>
            </transition>

            <!-- 快速执行按钮 -->
            <el-tooltip content="执行此步骤" placement="left">
              <el-button
                size="small"
                type="primary"
                circle
                class="absolute -right-9 top-1/2 -translate-y-1/2"
                :loading="executingStep === param.name"
                :disabled="!browserRunning || !selectedActionId"
                @click="executeSingleParam(param.name)"
              >
                <el-icon><VideoPlay /></el-icon>
              </el-button>
            </el-tooltip>
          </div>

          <div class="mt-1 flex items-center gap-2">
            <el-tag size="small" effect="plain" class="!text-[10px] !py-0 !px-1">
              {{ getParamTypeLabel(param) }}
            </el-tag>
            <span v-if="param.description && !compactMode" class="text-[10px] text-[var(--el-text-color-placeholder)]">
              {{ param.description }}
            </span>
          </div>
        </el-form-item>
      </el-form>
    </section>

    <!-- 无参数提示 -->
    <section v-else-if="selectedActionId && (!currentAction?.parameters || currentAction.parameters.length === 0)" class="no-params-hint bg-white rounded-lg border border-dashed border-[var(--el-border-color-lighter)] p-6 text-center shadow-sm">
      <el-icon :size="32" class="text-[var(--el-text-color-placeholder)]"><Document /></el-icon>
      <p class="text-sm text-[var(--el-text-color-secondary)] mt-2 m-0">此操作无需参数</p>
      <el-button size="small" type="primary" class="mt-3" :loading="executing" :disabled="!browserRunning" @click="execute">
        <el-icon><VideoPlay /></el-icon> 直接执行
      </el-button>
    </section>

    <!-- 未选择提示 -->
    <section v-else class="empty-state bg-white rounded-lg border border-dashed border-[var(--el-border-color-lighter)] p-8 text-center shadow-sm flex-1 flex flex-col items-center justify-center">
      <el-icon :size="48" class="text-[var(--el-text-color-placeholder)]"><Mouse /></el-icon>
      <p class="text-sm text-[var(--el-text-color-secondary)] mt-3 m-0">请从上方选择一个操作开始调试</p>
      <p v-if="compactMode" class="text-xs text-[var(--el-text-color-placeholder)] mt-1 m-0">紧凑模式下仅显示核心功能</p>
    </section>

    <!-- 截图预览区（紧凑模式时隐藏） -->
    <section v-if="lastScreenshotUrl && !compactMode" class="screenshot-preview bg-white rounded-lg border border-[var(--el-border-color-lighter)] p-2 shadow-sm">
      <div class="flex items-center justify-between mb-2">
        <label class="text-xs font-medium text-[var(--el-text-color-secondary)]">截图预览</label>
        <el-button size="small" text @click="emit('screenshot-updated', null)">清除</el-button>
      </div>
      <div class="relative rounded overflow-hidden border border-[var(--el-border-color-lighter)]" style="height: 150px">
        <img :src="lastScreenshotUrl" alt="截图" class="w-full h-full object-cover" />
      </div>
    </section>
  </div>
</template>

<script setup lang="ts">
import { ref, reactive, computed, inject } from 'vue'
import {
  Search, RefreshRight, InfoFilled, VideoPlay,
  Document, Mouse
} from '@element-plus/icons-vue'
import { ElMessage } from 'element-plus'
import debugApi from '@/api/browser/debug_api'

const props = defineProps<{
  browserId: string
  browserRunning: boolean
  registeredActions: Array<any>
  loadingActions: boolean
  compactMode?: boolean
}>()

const emit = defineEmits<{
  log: [message: string, type: 'info' | 'success' | 'warning' | 'error']
  screenshotUpdated: [url: string | null]
  variablesUpdated: [vars: Record<string, any>]
}>()

const addGlobalLog = inject('addGlobalLog') as (level: any, message: string, source?: string) => void

// 状态
const selectedActionId = ref('')
const actionParams = reactive<Record<string, any>>({})
const previewResults = ref<Record<string, string>>({})
const showPreview = ref<Record<string, boolean>>({})
const executing = ref(false)
const executingStep = ref<string | null>(null)
const lastScreenshotUrl = ref<string>()

// 计算属性
const currentAction = computed(() => props.registeredActions.find(a => a.id === selectedActionId.value))

const requiredParamsCount = computed(() =>
  currentAction.value?.parameters?.filter((p: any) => p.required).length || 0
)

const hasCustomParams = computed(() => {
  if (!currentAction.value?.parameters) return false
  return currentAction.value.parameters.some((p: any) => {
    const currentVal = actionParams[p.name]
    const defaultVal = p.default
    return JSON.stringify(currentVal) !== JSON.stringify(defaultVal)
  })
})

// 方法
const getActionIcon = (type: string): string => {
  const iconMap: Record<string, string> = {
    navigation: 'Location',
    interaction: 'Pointer',
    extraction: 'DocumentCopy',
    control_flow: 'Switch',
    utility: 'Tools',
    other: 'Setting'
  }
  return iconMap[type] || 'Setting'
}

const getParamTypeLabel = (param: any): string => {
  if (param.default === true || param.default === false) return '布尔'
  if (typeof param.default === 'number') return Number.isInteger(param.default) ? '整数' : '浮点'
  return '文本'
}

const onActionChange = () => {
  Object.keys(actionParams).forEach(k => delete actionParams[k])
  previewResults.value = {}
  showPreview.value = {}

  if (currentAction.value?.parameters) {
    currentAction.value.parameters.forEach((param: any) => {
      if (param.default !== undefined) {
        actionParams[param.name] = param.default
      }
    })
  }

  addGlobalLog?.('info', `已选择操作: ${currentAction.value?.name || selectedActionId.value}`)
  emit('log', `选择操作: ${currentAction.value?.name}`, 'info')
}

const resetParams = () => {
  if (!currentAction.value?.parameters) return

  currentAction.value.parameters.forEach((param: any) => {
    actionParams[param.name] = param.default ?? ''
  })

  previewResults.value = {}
  addGlobalLog?.('info', '参数已重置为默认值')
}

const onParamBlur = async (paramName: string) => {
  const val = actionParams[paramName]
  if (!val || typeof val !== 'string' || !val.includes('{{')) {
    delete previewResults[paramName]
    return
  }

  try {
    showPreview.value[paramName] = true
    const res = await debugApi.previewParams({
      params: { [paramName]: val },
      variables: {},
      template: val
    })

    if (res.code === 0 && res.data) {
      const resolved = res.data.resolved_params[paramName]
      previewResults.value[paramName] = resolved !== undefined
        ? resolved
        : res.data.resolved_template || '(无结果)'
    } else {
      previewResults.value[paramName] = `(错误) ${res.msg}`
    }
  } catch (e: any) {
    previewResults.value[paramName] = `(错误) ${e.message}`
  }
}

const executeSingleParam = async (_paramName?: string) => {
  await execute()
}

const execute = async () => {
  if (!props.browserRunning || !selectedActionId.value) return

  executing.value = true
  const startTime = Date.now()
  addGlobalLog?.('info', `▶ 开始执行: ${currentAction.value?.name}`)

  try {
    const res = await debugApi.executeStep({
      browser_id: props.browserId,
      action_id: selectedActionId.value,
      params: actionParams,
      page_index: 0
    })

    const duration = Date.now() - startTime

    if (res.code === 0 && res.data) {
      // 处理日志
      if (res.data.logs?.length) {
        res.data.logs.forEach((log: any) => {
          addGlobalLog?.(log.level === 'error' ? 'error' : log.level === 'plugin' ? 'plugin' : 'success', log.message, log.source)
        })
      }

      // 截图
      if (res.data.screenshot) {
        lastScreenshotUrl.value = res.data.screenshot
        emit('screenshot-updated', res.data.screenshot)
      }

      // 变量更新
      if (res.data.user_data) {
        emit('variablesUpdated', res.data.user_data)
      }

      if (res.data.success) {
        ElMessage.success(`执行成功 (${duration}ms)`)
        addGlobalLog?.('success', `✓ 执行成功 (${duration}ms)`)
        emit('log', `[调试] 成功`, 'success')
      } else {
        ElMessage.error(res.data.error || '执行失败')
        addGlobalLog?.('error', `✗ 执行失败: ${res.data.error}`)
        emit('log', `[调试] 失败`, 'error')
      }
    }
  } catch (e: any) {
    ElMessage.error(e.message)
    addGlobalLog?.('error', `异常: ${e.message}`)
  } finally {
    executing.value = false
    executingStep.value = null
  }
}

const reset = () => {
  selectedActionId.value = ''
  Object.keys(actionParams).forEach(k => delete actionParams[k])
  previewResults.value = {}
  showPreview.value = {}
}

const loadData = () => {
  addGlobalLog?.('info', '操作调试工作区已就绪')
}

defineExpose({ execute, reset, loadData })
</script>

<style scoped>
.action-debug-workspace {
  animation: fadeIn 0.2s ease-out;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(5px); }
  to { opacity: 1; transform: translateY(0); }
}
</style>
