          <el-icon :size="12"><Search /></el-icon>
          选择操作
        </label>
        <div class="flex items-center gap-2">
          <el-tag size="small" type="info" effect="plain">{{ registeredActions.length }} 个可用</el-tag>
          <el-button size="small" text @click="loadRegisteredActions" :loading="loadingActions">
            <el-icon><Refresh /></el-icon>
          </el-button>
        </div>
      </div>

      <el-select
        v-model="selectedActionId"
        placeholder="搜索或选择要调试的操作..."
        class="w-full"
        filterable
        clearable
        :loading="loadingActions"
        @change="onActionChange"
      >
        <template #prefix><el-icon><Search /></el-icon></template>
        <el-option-group v-for="group in actionGroups" :key="group.label" :label="group.label">
          <el-option
            v-for="action in group.actions"
            :key="action.id"
            :value="action.id"
            :label="action.name"
          >
            <div class="flex items-center gap-2 py-1">
              <el-icon :size="14" class="text-primary"><component :is="getActionIcon(action.type || 'interaction')" /></el-icon>
              <span class="flex-1">{{ action.name }}</span>
              <el-tag size="small" type="info" effect="plain" class="!text-[10px]">{{ action.type || 'other' }}</el-tag>
            </div>
          </el-option>
        </el-option-group>
      </el-select>

      <p v-if="currentAction?.description" class="text-xs text-[var(--el-text-color-secondary)] mt-2 mb-0 leading-relaxed line-clamp-2">
        {{ currentAction.description }}
      </p>
    </section>

    <!-- 主内容区：参数配置 + 执行控制 -->
    <section class="flex-1 min-h-0 overflow-y-auto mt-2 space-y-2">
      <!-- 参数配置区 -->
      <div v-if="currentAction?.parameters?.length > 0" class="params-config bg-white rounded-lg border border-[var(--el-border-color-lighter)] p-3 shadow-sm">
        <div class="flex items-center justify-between mb-3">
          <label class="text-xs font-medium text-[var(--el-text-color-secondary)] flex items-center gap-1">
            <el-icon><Setting /></el-icon> 参数配置
            <el-badge :value="requiredParamsCount" :max="99" class="ml-1" />
          </label>
          <div class="flex items-center gap-2">
            <el-button size="small" text @click="resetParams" :disabled="!hasCustomParams">
              <el-icon><RefreshRight /></el-icon> 重置
            </el-button>
            <el-button size="small" text @click="showVariableHelper = !showVariableHelper">
              <el-icon><QuestionFilled /></el-icon> 变量帮助
            </el-button>
          </div>
        </div>

        <!-- 变量帮助提示 -->
        <el-collapse-transition>
          <div v-if="showVariableHelper" class="mb-3 p-2 rounded-lg bg-blue-50 border border-blue-200 text-xs">
            <div class="font-medium text-blue-700 mb-1">变量模板语法</div>
            <div class="text-blue-600 space-y-1">
              <p><code class="bg-blue-100 px-1 rounded">{{ 变量名 }}</code> - 引用变量值</p>
              <p><code class="bg-blue-100 px-1 rounded">{{ $env.变量名 }}</code> - 引用环境变量</p>
              <p><code class="bg-blue-100 px-1 rounded">{{ $prev.result }}</code> - 引用上一步结果</p>
            </div>
          </div>
        </el-collapse-transition>

        <el-form label-position="top" size="small">
          <el-form-item
            v-for="param in currentAction.parameters"
            :key="param.name"
            :required="param.required"
            class="mb-3"
          >
            <template #label>
              <div class="flex items-center gap-1">
                <span>{{ param.name }}</span>
                <el-tooltip v-if="param.description" :content="param.description" placement="top">
                  <el-icon class="text-blue-500 cursor-help" :size="12"><InfoFilled /></el-icon>
                </el-tooltip>
                <!-- 变量预览指示器 -->
                <el-tooltip
                  v-if="isVariableReference(actionParams[param.name])"
                  :content="`预览: ${previewResults[param.name] || '解析中...'}`"
                  placement="top"
                  effect="light"
                >
                  <el-icon class="text-purple-500 cursor-help animate-pulse" :size="12"><MagicStick /></el-icon>
                </el-tooltip>
              </div>
            </template>

            <div class="relative">
              <!-- 根据参数类型渲染不同的输入组件 -->
              <template v-if="param.type === 'boolean'">
                <el-switch
                  v-model="actionParams[param.name]"
                  active-text="是"
                  inactive-text="否"
                />
              </template>
              <template v-else-if="param.type === 'int' || param.type === 'number' || param.type === 'float'">
                <el-input-number
                  v-model="actionParams[param.name]"
                  :placeholder="`默认: ${param.default ?? 0}`"
                  class="w-full"
                  controls-position="right"
                />
              </template>
              <template v-else-if="param.type === 'selector'">
                <el-input
                  v-model="actionParams[param.name]"
                  :placeholder="`CSS选择器，默认: ${param.default ?? '(空)'}`"
                  clearable
                  @blur="onParamBlur(param.name)"
                >
                  <template #append>
                    <el-button :icon="Aim" @click="openSelectorPicker(param.name)" />
                  </template>
                </el-input>
              </template>
              <template v-else-if="param.type === 'url'">
                <el-input
                  v-model="actionParams[param.name]"
                  :placeholder="`URL地址，默认: ${param.default ?? '(空)'}`"
                  clearable
                  @blur="onParamBlur(param.name)"
                >
                  <template #prepend>https://</template>
                </el-input>
              </template>
              <template v-else-if="param.type === 'code'">
                <div class="w-full">
                  <el-input
                    v-model="actionParams[param.name]"
                    type="textarea"
                    :rows="4"
                    :placeholder="`JavaScript代码，默认: ${param.default ?? '(空)'}`"
                    @blur="onParamBlur(param.name)"
