                      <el-icon><Document /></el-icon> 格式化
                    </el-button>
                  </div>
                </div>
              </template>
              <template v-else-if="param.type === 'array'">
                <el-select
                  v-model="actionParams[param.name]"
                  multiple
                  filterable
                  allow-create
                  default-first-option
                  :reserve-keyword="false"
                  placeholder="输入后回车添加"
                  class="w-full"
                />
              </template>
