          <el-option
            v-for="action in group.actions"
            :key="action.id"
            :value="action.id"
            :label="action.name"
          >
            <div class="flex items-center gap-2 py-1">
              <el-icon :size="14" class="text-primary"><component :is="getActionIcon(action.type || 'interaction')" /></el-icon>
              <span class="flex-1">{{ action.name }}</span>
              <el-tag size="small" type="info" effect="plain" class="!text-[10px]">{{ action.type || 'other' }}</el-tag>
            </div>
          </el-option>
        </el-option-group>
      </el-select>

      <p v-if="currentAction?.description" class="text-xs text-[var(--el-text-color-secondary)] mt-2 mb-0 leading-relaxed line-clamp-2">
        {{ currentAction.description }}
      </p>
    </section>

    <!-- 主内容区：参数配置 + 执行控制 -->
    <section class="flex-1 min-h-0 overflow-y-auto mt-2 space-y-2">
      <!-- 参数配置区 -->
      <div v-if="currentAction?.parameters?.length > 0" class="params-config bg-white rounded-lg border border-[var(--el-border-color-lighter)] p-3 shadow-sm">
