          </label>
          <div class="flex items-center gap-2">
            <el-button size="small" text @click="resetParams" :disabled="!hasCustomParams">
              <el-icon><RefreshRight /></el-icon> 重置
            </el-button>
            <el-button size="small" text @click="showVariableHelper = !showVariableHelper">
              <el-icon><QuestionFilled /></el-icon> 变量帮助
            </el-button>
          </div>
        </div>

        <!-- 变量帮助提示 -->
        <el-collapse-transition>
          <div v-if="showVariableHelper" class="mb-3 p-2 rounded-lg bg-blue-50 border border-blue-200 text-xs">
