              <p><code class="bg-blue-100 px-1 rounded">{{ $env.变量名 }}</code> - 引用环境变量</p>
              <p><code class="bg-blue-100 px-1 rounded">{{ $prev.result }}</code> - 引用上一步结果</p>
            </div>
          </div>
