              <div class="flex items-center gap-1">
                <span>{{ param.name }}</span>
                <el-tooltip v-if="param.description" :content="param.description" placement="top">
                  <el-icon class="text-blue-500 cursor-help" :size="12"><InfoFilled /></el-icon>
                </el-tooltip>
                <!-- 变量预览指示器 -->
                <el-tooltip
                  v-if="isVariableReference(actionParams[param.name])"
                  :content="`预览: ${previewResults[param.name] || '解析中...'}`"
                  placement="top"
                  effect="light"
                >
                  <el-icon class="text-purple-500 cursor-help animate-pulse" :size="12"><MagicStick /></el-icon>
                </el-tooltip>
              </div>
            </template>

            <div class="relative">
              <!-- 根据参数类型渲染不同的输入组件 -->
              <template v-if="param.type === 'boolean'">
                <el-switch
                  v-model="actionParams[param.name]"
                  active-text="是"
                  inactive-text="否"
                />
              </template>
              <template v-else-if="param.type === 'int' || param.type === 'number' || param.type === 'float'">
                <el-input-number
                  v-model="actionParams[param.name]"
                  :placeholder="`默认: ${param.default ?? 0}`"
                  class="w-full"
                  controls-position="right"
                />
              </template>
              <template v-else-if="param.type === 'selector'">
                <el-input
                  v-model="actionParams[param.name]"
                  :placeholder="`CSS选择器，默认: ${param.default ?? '(空)'}`"
                  clearable
                  @blur="onParamBlur(param.name)"
                >
                  <template #append>
                    <el-button :icon="Aim" @click="openSelectorPicker(param.name)" />
                  </template>
                </el-input>
              </template>
              <template v-else-if="param.type === 'url'">
                <el-input
                  v-model="actionParams[param.name]"
                  :placeholder="`URL地址，默认: ${param.default ?? '(空)'}`"
                  clearable
                  @blur="onParamBlur(param.name)"
                >
                  <template #prepend>https://</template>
                </el-input>
              </template>
              <template v-else-if="param.type === 'code'">
                <div class="w-full">
                  <el-input
                    v-model="actionParams[param.name]"
                    type="textarea"
                    :rows="4"
                    :placeholder="`JavaScript代码，默认: ${param.default ?? '(空)'}`"
                    @blur="onParamBlur(param.name)"
                  />
                  <div class="flex justify-end mt-1">
                    <el-button size="small" text @click="formatCode(param.name)">
                      <el-icon><Document /></el-icon> 格式化
                    </el-button>
                  </div>
                </div>
              </template>
              <template v-else-if="param.type === 'array'">
                <el-select
                  v-model="actionParams[param.name]"
                  multiple
                  filterable
                  allow-create
                  default-first-option
                  :reserve-keyword="false"
                  placeholder="输入后回车添加"
                  class="w-full"
                />
              </template>
              <template v-else>
                <el-input
                  v-model="actionParams[param.name]"
                  :placeholder="`默认: ${param.default ?? '(空)'}`"
                  clearable
                  @blur="onParamBlur(param.name)"
                />
              </template>

              <!-- 预览结果气泡 -->
              <transition name="el-zoom-in-top">
                <div
                  v-if="previewResults[param.name] && showPreview[param.name]"
                  class="absolute z-20 top-full left-0 right-0 mt-1 p-2 rounded-lg shadow-lg text-xs font-mono"
                  :class="previewResults[param.name].startsWith('(错误)') ? 'bg-red-50 text-red-700 border border-red-200' : 'bg-green-50 text-green-700 border border-green-200'"
                >
                  {{ previewResults[param.name] }}
                </div>
              </transition>
            </div>

            <div class="mt-1 flex items-center gap-2">
              <el-tag size="small" effect="plain" class="!text-[10px] !py-0 !px-1">
                {{ getParamTypeLabel(param) }}
              </el-tag>
              <span v-if="param.description" class="text-[10px] text-[var(--el-text-color-placeholder)] truncate">
                {{ param.description }}
              </span>
            </div>
          </el-form-item>
        </el-form>
      </div>

      <!-- 无参数提示 -->
      <div v-else-if="selectedActionId && (!currentAction?.parameters || currentAction.parameters.length === 0)" class="no-params-hint bg-white rounded-lg border border-dashed border-[var(--el-border-color-lighter)] p-6 text-center shadow-sm">
        <el-icon :size="32" class="text-[var(--el-text-color-placeholder)]"><Document /></el-icon>
        <p class="text-sm text-[var(--el-text-color-secondary)] mt-2 m-0">此操作无需参数配置</p>
      </div>

