      <div v-else class="empty-state bg-white rounded-lg border border-dashed border-[var(--el-border-color-lighter)] p-8 text-center shadow-sm flex-1 flex flex-col items-center justify-center">
        <el-icon :size="48" class="text-[var(--el-text-color-placeholder)]"><Mouse /></el-icon>
        <p class="text-sm text-[var(--el-text-color-secondary)] mt-3 m-0">请从上方选择一个操作开始调试</p>
        <p class="text-xs text-[var(--el-text-color-placeholder)] mt-1 m-0">支持变量模板语法 {{ 变量名 }}</p>
      </div>

      <!-- 执行控制区 -->
      <div v-if="selectedActionId" class="execution-controls bg-white rounded-lg border border-[var(--el-border-color-lighter)] p-3 shadow-sm shrink-0">
        <div class="flex items-center justify-between mb-2">
          <span class="text-xs font-medium text-[var(--el-text-color-secondary)]">执行控制</span>
          <el-checkbox v-model="dryRunMode" size="small">
            <span class="text-xs">试运行模式</span>
          </el-checkbox>
        </div>
        <div class="flex items-center gap-2">
          <el-button
            type="primary"
            :loading="executing"
            :disabled="!browserRunning || !canExecute"
            @click="execute"
          >
            <el-icon><VideoPlay /></el-icon> 执行操作
          </el-button>
          <el-button @click="previewExecution" :disabled="!browserRunning || !selectedActionId">
            <el-icon><View /></el-icon> 预览
          </el-button>
          <el-button @click="validateParams" :disabled="!selectedActionId">
            <el-icon><CircleCheck /></el-icon> 验证
          </el-button>
          <div class="flex-1"></div>
          <el-button v-if="lastExecutionResult" type="success" @click="saveAsCustomAction">
            <el-icon><FolderAdd /></el-icon> 保存为自定义操作
          </el-button>
        </div>
      </div>

      <!-- 执行结果区 -->
      <div v-if="lastExecutionResult" class="execution-result bg-white rounded-lg border border-[var(--el-border-color-lighter)] p-3 shadow-sm shrink-0">
        <div class="flex items-center justify-between mb-2">
          <span class="text-xs font-medium text-[var(--el-text-color-secondary)]">执行结果</span>
          <div class="flex items-center gap-2">
            <el-tag :type="lastExecutionResult.success ? 'success' : 'danger'" size="small">
              {{ lastExecutionResult.success ? '成功' : '失败' }}
