<template>
  <div class="action-debug-workspace flex flex-col h-full overflow-hidden">
    <!-- 顶部操作选择区 -->
    <section class="action-selector bg-white rounded-lg border border-[var(--el-border-color-lighter)] p-3 shadow-sm shrink-0">
