            <el-badge :value="requiredParamsCount" :max="99" class="ml-1" />
          </label>
          <div class="flex items-center gap-2">
            <el-button size="small" text @click="resetParams" :disabled="!hasCustomParams">
              <el-icon><RefreshRight /></el-icon> 重置
            </el-button>
            <el-button size="small" text @click="showVariableHelper = !showVariableHelper">
              <el-icon><QuestionFilled /></el-icon> 变量帮助
            </el-button>
          </div>
        </div>

        <!-- 变量帮助提示 -->
        <el-collapse-transition>
          <div v-if="showVariableHelper" class="mb-3 p-2 rounded-lg bg-blue-50 border border-blue-200 text-xs">
            <div class="font-medium text-blue-700 mb-1">变量模板语法</div>
            <div class="text-blue-600 space-y-1">
              <p><code class="bg-blue-100 px-1 rounded">{{ 变量名 }}</code> - 引用变量值</p>
              <p><code class="bg-blue-100 px-1 rounded">{{ $env.变量名 }}</code> - 引用环境变量</p>
              <p><code class="bg-blue-100 px-1 rounded">{{ $prev.result }}</code> - 引用上一步结果</p>
            </div>
          </div>
        </el-collapse-transition>

        <el-form label-position="top" size="small">
          <el-form-item
            v-for="param in currentAction.parameters"
            :key="param.name"
            :required="param.required"
            class="mb-3"
          >
            <template #label>
              <div class="flex items-center gap-1">
                <span>{{ param.name }}</span>
                <el-tooltip v-if="param.description" :content="param.description" placement="top">
                  <el-icon class="text-blue-500 cursor-help" :size="12"><InfoFilled /></el-icon>
                </el-tooltip>
                <!-- 变量预览指示器 -->
                <el-tooltip
                  v-if="isVariableReference(actionParams[param.name])"
                  :content="`预览: ${previewResults[param.name] || '解析中...'}`"
                  placement="top"
                  effect="light"
                >
                  <el-icon class="text-purple-500 cursor-help animate-pulse" :size="12"><MagicStick /></el-icon>
                </el-tooltip>
              </div>
            </template>

            <div class="relative">
              <!-- 根据参数类型渲染不同的输入组件 -->
              <template v-if="param.type === 'boolean'">
                <el-switch
                  v-model="actionParams[param.name]"
                  active-text="是"
                  inactive-text="否"
                />
              </template>
              <template v-else-if="param.type === 'int' || param.type === 'number' || param.type === 'float'">
                <el-input-number
                  v-model="actionParams[param.name]"
                  :placeholder="`默认: ${param.default ?? 0}`"
                  class="w-full"
                  controls-position="right"
                />
              </template>
              <template v-else-if="param.type === 'selector'">
                <el-input
                  v-model="actionParams[param.name]"
                  :placeholder="`CSS选择器，默认: ${param.default ?? '(空)'}`"
                  clearable
                  @blur="onParamBlur(param.name)"
                >
                  <template #append>
                    <el-button :icon="Aim" @click="openSelectorPicker(param.name)" />
                  </template>
                </el-input>
              </template>
              <template v-else-if="param.type === 'url'">
                <el-input
                  v-model="actionParams[param.name]"
                  :placeholder="`URL地址，默认: ${param.default ?? '(空)'}`"
                  clearable
                  @blur="onParamBlur(param.name)"
                >
                  <template #prepend>https://</template>
                </el-input>
              </template>
              <template v-else-if="param.type === 'code'">
                <div class="w-full">
                  <el-input
                    v-model="actionParams[param.name]"
                    type="textarea"
                    :rows="4"
                    :placeholder="`JavaScript代码，默认: ${param.default ?? '(空)'}`"
                    @blur="onParamBlur(param.name)"
                  />
                  <div class="flex justify-end mt-1">
                    <el-button size="small" text @click="formatCode(param.name)">
                      <el-icon><Document /></el-icon> 格式化
                    </el-button>
                  </div>
                </div>
              </template>
              <template v-else-if="param.type === 'array'">
                <el-select
                  v-model="actionParams[param.name]"
                  multiple
                  filterable
                  allow-create
                  default-first-option
                  :reserve-keyword="false"
                  placeholder="输入后回车添加"
                  class="w-full"
                />
              </template>
              <template v-else>
                <el-input
                  v-model="actionParams[param.name]"
                  :placeholder="`默认: ${param.default ?? '(空)'}`"
                  clearable
                  @blur="onParamBlur(param.name)"
                />
              </template>

              <!-- 预览结果气泡 -->
              <transition name="el-zoom-in-top">
                <div
                  v-if="previewResults[param.name] && showPreview[param.name]"
                  class="absolute z-20 top-full left-0 right-0 mt-1 p-2 rounded-lg shadow-lg text-xs font-mono"
                  :class="previewResults[param.name].startsWith('(错误)') ? 'bg-red-50 text-red-700 border border-red-200' : 'bg-green-50 text-green-700 border border-green-200'"
                >
                  {{ previewResults[param.name] }}
                </div>
              </transition>
            </div>

            <div class="mt-1 flex items-center gap-2">
              <el-tag size="small" effect="plain" class="!text-[10px] !py-0 !px-1">
                {{ getParamTypeLabel(param) }}
              </el-tag>
              <span v-if="param.description" class="text-[10px] text-[var(--el-text-color-placeholder)] truncate">
                {{ param.description }}
              </span>
            </div>
          </el-form-item>
        </el-form>
      </div>

      <!-- 无参数提示 -->
      <div v-else-if="selectedActionId && (!currentAction?.parameters || currentAction.parameters.length === 0)" class="no-params-hint bg-white rounded-lg border border-dashed border-[var(--el-border-color-lighter)] p-6 text-center shadow-sm">
        <el-icon :size="32" class="text-[var(--el-text-color-placeholder)]"><Document /></el-icon>
        <p class="text-sm text-[var(--el-text-color-secondary)] mt-2 m-0">此操作无需参数配置</p>
      </div>

      <!-- 未选择提示 -->
      <div v-else class="empty-state bg-white rounded-lg border border-dashed border-[var(--el-border-color-lighter)] p-8 text-center shadow-sm flex-1 flex flex-col items-center justify-center">
        <el-icon :size="48" class="text-[var(--el-text-color-placeholder)]"><Mouse /></el-icon>
        <p class="text-sm text-[var(--el-text-color-secondary)] mt-3 m-0">请从上方选择一个操作开始调试</p>
        <p class="text-xs text-[var(--el-text-color-placeholder)] mt-1 m-0">支持变量模板语法 {{ 变量名 }}</p>
      </div>

      <!-- 执行控制区 -->
      <div v-if="selectedActionId" class="execution-controls bg-white rounded-lg border border-[var(--el-border-color-lighter)] p-3 shadow-sm shrink-0">
        <div class="flex items-center justify-between mb-2">
          <span class="text-xs font-medium text-[var(--el-text-color-secondary)]">执行控制</span>
          <el-checkbox v-model="dryRunMode" size="small">
            <span class="text-xs">试运行模式</span>
          </el-checkbox>
        </div>
        <div class="flex items-center gap-2">
          <el-button
            type="primary"
            :loading="executing"
            :disabled="!browserRunning || !canExecute"
            @click="execute"
          >
            <el-icon><VideoPlay /></el-icon> 执行操作
          </el-button>
          <el-button @click="previewExecution" :disabled="!browserRunning || !selectedActionId">
            <el-icon><View /></el-icon> 预览
          </el-button>
          <el-button @click="validateParams" :disabled="!selectedActionId">
            <el-icon><CircleCheck /></el-icon> 验证
          </el-button>
          <div class="flex-1"></div>
          <el-button v-if="lastExecutionResult" type="success" @click="saveAsCustomAction">
            <el-icon><FolderAdd /></el-icon> 保存为自定义操作
          </el-button>
        </div>
      </div>

      <!-- 执行结果区 -->
      <div v-if="lastExecutionResult" class="execution-result bg-white rounded-lg border border-[var(--el-border-color-lighter)] p-3 shadow-sm shrink-0">
        <div class="flex items-center justify-between mb-2">
          <span class="text-xs font-medium text-[var(--el-text-color-secondary)]">执行结果</span>
          <div class="flex items-center gap-2">
            <el-tag :type="lastExecutionResult.success ? 'success' : 'danger'" size="small">
              {{ lastExecutionResult.success ? '成功' : '失败' }}
            </el-tag>
            <span class="text-xs text-[var(--el-text-color-placeholder)]">
              耗时: {{ lastExecutionResult.executionTime }}ms
            </span>
          </div>
        </div>
        
        <!-- 截图预览 -->
        <div v-if="lastExecutionResult.screenshot" class="mb-2">
          <div class="flex items-center justify-between mb-1">
            <span class="text-xs text-[var(--el-text-color-secondary)]">截图</span>
            <el-button size="small" text @click="openScreenshotFullscreen">
              <el-icon><FullScreen /></el-icon> 全屏
            </el-button>
          </div>
          <img 
            :src="lastExecutionResult.screenshot" 
            class="w-full rounded border border-[var(--el-border-color-lighter)] cursor-pointer hover:opacity-80 transition-opacity"
            style="max-height: 200px; object-fit: contain;"
            @click="openScreenshotFullscreen"
          />
        </div>

        <!-- 返回数据 -->
        <div v-if="lastExecutionResult.result">
          <div class="text-xs text-[var(--el-text-color-secondary)] mb-1">返回数据</div>
          <vue-json-pretty 
            :data="lastExecutionResult.result" 
            :deep="2"
            class="text-xs bg-[var(--el-fill-color-lighter)] p-2 rounded max-h-40 overflow-auto"
          />
        </div>

        <!-- 错误信息 -->
        <div v-if="lastExecutionResult.error" class="mt-2 p-2 rounded bg-red-50 border border-red-200">
          <div class="text-xs text-red-700 font-medium">错误信息</div>
          <pre class="text-xs text-red-600 mt-1 whitespace-pre-wrap">{{ lastExecutionResult.error }}</pre>
        </div>
      </div>

      <!-- 执行日志区 -->
      <div v-if="executionLogs.length > 0" class="execution-logs bg-white rounded-lg border border-[var(--el-border-color-lighter)] shadow-sm shrink-0 max-h-48 overflow-hidden flex flex-col">
        <div class="flex items-center justify-between px-3 py-2 border-b border-[var(--el-border-color-lighter)] shrink-0">
          <span class="text-xs font-medium text-[var(--el-text-color-secondary)]">执行日志</span>
          <el-button size="small" text @click="clearLogs">
            <el-icon><Delete /></el-icon> 清空
          </el-button>
        </div>
        <div ref="logsContainerRef" class="flex-1 overflow-y-auto p-2 space-y-1">
          <div
            v-for="(log, idx) in executionLogs"
